def parse_date(s):
    if not s:
        return None
    s = s.lower()
    patterns = [
        (r'(\d{1,2})(?:st|nd|rd|th)?\s+(\w{3,})\s+(\d{4})', lambda m: (int(m.group(1)), months.get(m.group(2)[:3],0), int(m.group(3)))),
        (r'(\w{3,})\s+(\d{1,2})(?:st|nd|rd|th)?,?\s+(\d{4})', lambda m: (int(m.group(2)), months.get(m.group(1)[:3],0), int(m.group(3)))),
    ]
