    if grant_date and 2015 <= grant_date.year <= 2020:
        year = grant_date.year
        years.add(year)

        if year not in cpc4_yearly_counts:
            cpc4_yearly_counts[year] = {}

        cpc_data = p.get('cpc', '')
        codes = re.findall(r'"code":\s*"([^"]+)"', cpc_data)
        for code in codes:
            m = re.match(r'^([A-Z]\d{2}[A-Z]\d)/\d+', code)
            if m:
                cpc4 = m.group(1) + '/00'
