def parse_date(s):
    if not s or not isinstance(s, str):
        return None
    s = s.lower()
    for pat, idx_day, idx_mon, idx_year in [(r'(\d{1,2})(?:st|nd|rd|th)?\s+(\w{3,})\s+(\d{4})', 1, 2, 3), (r'(\w{3,})\s+(\d{1,2})(?:st|nd|rd|th)?,?\s+(\d{4})', 2, 1, 3)]:
